let content = fs.readFileSync('src/data/fields.ts', 'utf8');
const insertPoint = content.lastIndexOf('};');

let newContent = '';
for (const [sourceId, fields] of Object.entries(newFields)) {
  newContent += `,\n  '${sourceId}': [\n`;
  fields.forEach((f, i) => {
    const desc = f.description.replace(/'/g, "\\'");
    const notes = f.notes.replace(/'/g, "\\'");
    newContent += `    { field: '${f.field}', description: '${desc}', securitySiem: '${f.securitySiem}', observability: '${f.observability}', fullFidelity: '${f.fullFidelity}', canDrop: '${f.canDrop}', canMask: '${f.canMask}', guardAction: '${f.guardAction}', notes: '${notes}' }${i < fields.length - 1 ? ',' : ''}\n`;
  });
  newContent += '  ]';
}

content = content.slice(0, insertPoint - 1) + newContent + '\n};\n';
fs.writeFileSync('src/data/fields.ts', content);
console.log('Batch 2 complete: Added', Object.keys(newFields).length, 'source field matrices');
